import{_ as a,o as s,c as n,ag as d}from"./chunks/framework.BVdG3tbf.js";const b=JSON.parse('{"title":"COMSOL 界面介绍","description":"","frontmatter":{},"headers":[],"relativePath":"comsol/basics/interface.md","filePath":"comsol/basics/interface.md","lastUpdated":1774417890000}'),e={name:"comsol/basics/interface.md"};function l(r,t,i,p,h,o){return s(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="comsol-界面介绍" tabindex="-1">COMSOL 界面介绍 <a class="header-anchor" href="#comsol-界面介绍" aria-label="Permalink to &quot;COMSOL 界面介绍&quot;">​</a></h1><p>本节介绍 COMSOL Multiphysics 的主要界面元素和基本操作。</p><h2 id="🖥️-主界面布局" tabindex="-1">🖥️ 主界面布局 <a class="header-anchor" href="#🖥️-主界面布局" aria-label="Permalink to &quot;🖥️ 主界面布局&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  菜单栏  文件  编辑  视图  组件  物理场  网格  研究  结果  帮助  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  工具栏  [保存] [撤销] [重做] [放大] [缩小] [旋转] [计算]     │</span></span>
<span class="line"><span>├──────────┬──────────────────────────────┬───────────────┤</span></span>
<span class="line"><span>│          │                              │               │</span></span>
<span class="line"><span>│  模型树   │        图形窗口              │   设置面板    │</span></span>
<span class="line"><span>│          │                              │               │</span></span>
<span class="line"><span>│  ● 组件1  │      ┌──────────┐           │   名称:       │</span></span>
<span class="line"><span>│    ├ 几何 │      │          │           │   ___         │</span></span>
<span class="line"><span>│    ├ 材料 │      │  3D 模型  │           │   参数:       │</span></span>
<span class="line"><span>│    ├ 物理场│      │          │           │   ___         │</span></span>
<span class="line"><span>│    ├ 网格 │      └──────────┘           │               │</span></span>
<span class="line"><span>│    └ 研究 │                              │               │</span></span>
<span class="line"><span>│          │                              │               │</span></span>
<span class="line"><span>├──────────┴──────────────────────────────┴───────────────┤</span></span>
<span class="line"><span>│  状态栏  坐标: (0, 0, 0)  选择: 面  内存: 2.3 GB         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="📋-主要组件详解" tabindex="-1">📋 主要组件详解 <a class="header-anchor" href="#📋-主要组件详解" aria-label="Permalink to &quot;📋 主要组件详解&quot;">​</a></h2><h3 id="_1-模型树-model-tree" tabindex="-1">1. 模型树（Model Tree） <a class="header-anchor" href="#_1-模型树-model-tree" aria-label="Permalink to &quot;1. 模型树（Model Tree）&quot;">​</a></h3><p>模型树是 COMSOL 的核心导航工具，显示仿真的完整结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📦 模型</span></span>
<span class="line"><span>├── 📁 组件 1</span></span>
<span class="line"><span>│   ├── 📐 几何 1</span></span>
<span class="line"><span>│   │   ├── 矩形 1</span></span>
<span class="line"><span>│   │   └── 圆形 1</span></span>
<span class="line"><span>│   ├── 🧱 材料</span></span>
<span class="line"><span>│   │   └── 材料 1 (Steel)</span></span>
<span class="line"><span>│   ├── ⚡ 物理场</span></span>
<span class="line"><span>│   │   ├── 固体传热 (ht)</span></span>
<span class="line"><span>│   │   └── 初始温度</span></span>
<span class="line"><span>│   ├── 🔲 网格 1</span></span>
<span class="line"><span>│   │   ├── 自由四面体</span></span>
<span class="line"><span>│   │   └── 大小设置</span></span>
<span class="line"><span>│   └── 📊 研究 1</span></span>
<span class="line"><span>│       ├── 稳态</span></span>
<span class="line"><span>│       └── 求解器配置</span></span>
<span class="line"><span>└── 📈 结果</span></span>
<span class="line"><span>    ├── 温度 (ht)</span></span>
<span class="line"><span>    └── 绘图组</span></span></code></pre></div><p><strong>常用操作：</strong></p><ul><li><strong>右键菜单</strong>：添加/编辑/删除节点</li><li><strong>双击</strong>：打开设置面板</li><li><strong>拖拽</strong>：调整节点顺序</li></ul><h3 id="_2-图形窗口-graphics-window" tabindex="-1">2. 图形窗口（Graphics Window） <a class="header-anchor" href="#_2-图形窗口-graphics-window" aria-label="Permalink to &quot;2. 图形窗口（Graphics Window）&quot;">​</a></h3><p>图形窗口用于显示几何模型和仿真结果。</p><p><strong>视图控制：</strong></p><table tabindex="0"><thead><tr><th>操作</th><th>鼠标</th><th>快捷键</th></tr></thead><tbody><tr><td>旋转</td><td>左键拖动</td><td>-</td></tr><tr><td>缩放</td><td>滚轮</td><td>Ctrl + 滚轮</td></tr><tr><td>平移</td><td>中键拖动</td><td>Shift + 左键</td></tr><tr><td>适合窗口</td><td>双击中键</td><td>Ctrl + F</td></tr><tr><td>放大区域</td><td>-</td><td>Ctrl + 框选</td></tr></tbody></table><p><strong>选择工具：</strong></p><table tabindex="0"><thead><tr><th>工具</th><th>图标</th><th>功能</th><th>快捷键</th></tr></thead><tbody><tr><td>点选择</td><td>🔵</td><td>选择顶点</td><td>1</td></tr><tr><td>边选择</td><td>📏</td><td>选择边</td><td>2</td></tr><tr><td>面选择</td><td>⬜</td><td>选择面</td><td>3</td></tr><tr><td>体选择</td><td>📦</td><td>选择体</td><td>4</td></tr><tr><td>全选</td><td>✅</td><td>选择所有</td><td>Ctrl+A</td></tr></tbody></table><h3 id="_3-设置面板-settings-panel" tabindex="-1">3. 设置面板（Settings Panel） <a class="header-anchor" href="#_3-设置面板-settings-panel" aria-label="Permalink to &quot;3. 设置面板（Settings Panel）&quot;">​</a></h3><p>设置面板显示当前选中项的详细参数。</p><p><strong>常见输入类型：</strong></p><ul><li><strong>文本框</strong>：输入数值或表达式</li><li><strong>下拉框</strong>：选择预设选项</li><li><strong>复选框</strong>：开关选项</li><li><strong>单位选择</strong>：选择物理单位</li></ul><p><strong>表达式输入示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10[W/m^2*K]     # 热流密度</span></span>
<span class="line"><span>25[degC]        # 温度</span></span>
<span class="line"><span>sin(omega*t)    # 时变函数</span></span>
<span class="line"><span>mat1.k(T)       # 温度相关热导率</span></span></code></pre></div><h2 id="🎛️-菜单栏详解" tabindex="-1">🎛️ 菜单栏详解 <a class="header-anchor" href="#🎛️-菜单栏详解" aria-label="Permalink to &quot;🎛️ 菜单栏详解&quot;">​</a></h2><h3 id="文件菜单" tabindex="-1">文件菜单 <a class="header-anchor" href="#文件菜单" aria-label="Permalink to &quot;文件菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>快捷键</th><th>说明</th></tr></thead><tbody><tr><td>新建模型</td><td>Ctrl+N</td><td>创建新项目</td></tr><tr><td>打开</td><td>Ctrl+O</td><td>打开已有模型</td></tr><tr><td>保存</td><td>Ctrl+S</td><td>保存当前模型</td></tr><tr><td>另存为</td><td>Ctrl+Shift+S</td><td>保存为新文件</td></tr><tr><td>导出</td><td>-</td><td>导出图像/数据</td></tr><tr><td>模型库</td><td>-</td><td>浏览案例库</td></tr></tbody></table><h3 id="组件菜单" tabindex="-1">组件菜单 <a class="header-anchor" href="#组件菜单" aria-label="Permalink to &quot;组件菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>几何</td><td>创建和编辑几何</td></tr><tr><td>材料</td><td>定义材料属性</td></tr><tr><td>定义</td><td>定义变量和函数</td></tr></tbody></table><h3 id="物理场菜单" tabindex="-1">物理场菜单 <a class="header-anchor" href="#物理场菜单" aria-label="Permalink to &quot;物理场菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>添加物理场</td><td>打开物理场接口浏览器</td></tr><tr><td>边界条件</td><td>设置边界条件</td></tr><tr><td>初始条件</td><td>设置初始值</td></tr></tbody></table><h3 id="网格菜单" tabindex="-1">网格菜单 <a class="header-anchor" href="#网格菜单" aria-label="Permalink to &quot;网格菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>全局定义</td><td>全局网格设置</td></tr><tr><td>局部定义</td><td>局部网格细化</td></tr><tr><td>生成网格</td><td>执行网格划分</td></tr></tbody></table><h3 id="研究菜单" tabindex="-1">研究菜单 <a class="header-anchor" href="#研究菜单" aria-label="Permalink to &quot;研究菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>添加研究</td><td>创建新的研究</td></tr><tr><td>步骤设置</td><td>配置求解步骤</td></tr><tr><td>计算</td><td>运行仿真</td></tr><tr><td>批处理</td><td>批量计算</td></tr></tbody></table><h3 id="结果菜单" tabindex="-1">结果菜单 <a class="header-anchor" href="#结果菜单" aria-label="Permalink to &quot;结果菜单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>2D 绘图组</td><td>创建 2D 图表</td></tr><tr><td>3D 绘图组</td><td>创建 3D 可视化</td></tr><tr><td>派生值</td><td>计算积分/平均值</td></tr><tr><td>报告</td><td>生成报告</td></tr></tbody></table><h2 id="⌨️-常用快捷键" tabindex="-1">⌨️ 常用快捷键 <a class="header-anchor" href="#⌨️-常用快捷键" aria-label="Permalink to &quot;⌨️ 常用快捷键&quot;">​</a></h2><h3 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Ctrl+N</td><td>新建</td></tr><tr><td>Ctrl+O</td><td>打开</td></tr><tr><td>Ctrl+S</td><td>保存</td></tr><tr><td>Ctrl+P</td><td>打印/导出图像</td></tr></tbody></table><h3 id="编辑操作" tabindex="-1">编辑操作 <a class="header-anchor" href="#编辑操作" aria-label="Permalink to &quot;编辑操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Ctrl+Z</td><td>撤销</td></tr><tr><td>Ctrl+Y</td><td>重做</td></tr><tr><td>Ctrl+C</td><td>复制</td></tr><tr><td>Ctrl+V</td><td>粘贴</td></tr><tr><td>Delete</td><td>删除</td></tr></tbody></table><h3 id="视图操作" tabindex="-1">视图操作 <a class="header-anchor" href="#视图操作" aria-label="Permalink to &quot;视图操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Ctrl+F</td><td>适合窗口</td></tr><tr><td>Ctrl+滚轮</td><td>缩放</td></tr><tr><td>F5</td><td>刷新图形</td></tr><tr><td>F7</td><td>计算</td></tr><tr><td>F12</td><td>显示/隐藏网格</td></tr></tbody></table><h2 id="💡-实用技巧" tabindex="-1">💡 实用技巧 <a class="header-anchor" href="#💡-实用技巧" aria-label="Permalink to &quot;💡 实用技巧&quot;">​</a></h2><h3 id="技巧-1-快速访问常用功能" tabindex="-1">技巧 1：快速访问常用功能 <a class="header-anchor" href="#技巧-1-快速访问常用功能" aria-label="Permalink to &quot;技巧 1：快速访问常用功能&quot;">​</a></h3><p>将常用功能添加到快捷工具栏：</p><ol><li>右键点击工具栏空白处</li><li>选择&quot;自定义&quot;</li><li>拖动常用按钮到工具栏</li></ol><h3 id="技巧-2-使用参数化设计" tabindex="-1">技巧 2：使用参数化设计 <a class="header-anchor" href="#技巧-2-使用参数化设计" aria-label="Permalink to &quot;技巧 2：使用参数化设计&quot;">​</a></h3><p>在 <strong>定义 → 参数</strong> 中定义参数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>名称: L</span></span>
<span class="line"><span>表达式: 0.1[m]</span></span>
<span class="line"><span>描述: 长度</span></span></code></pre></div><p>然后在几何或材料设置中使用 <code>L</code>。</p><h3 id="技巧-3-利用选择集" tabindex="-1">技巧 3：利用选择集 <a class="header-anchor" href="#技巧-3-利用选择集" aria-label="Permalink to &quot;技巧 3：利用选择集&quot;">​</a></h3><ol><li>选择多个几何实体</li><li>右键 → 创建选择</li><li>为选择集命名</li><li>在边界条件中直接使用选择集</li></ol><h3 id="技巧-4-查看计算日志" tabindex="-1">技巧 4：查看计算日志 <a class="header-anchor" href="#技巧-4-查看计算日志" aria-label="Permalink to &quot;技巧 4：查看计算日志&quot;">​</a></h3><p>计算完成后，点击 <strong>研究 → 显示日志</strong> 查看：</p><ul><li>计算时间</li><li>内存使用</li><li>收敛信息</li><li>警告/错误</li></ul><h2 id="📖-下一步" tabindex="-1">📖 下一步 <a class="header-anchor" href="#📖-下一步" aria-label="Permalink to &quot;📖 下一步&quot;">​</a></h2><ul><li><a href="/simu-learn/comsol/basics/geometry.html">几何建模</a></li><li><a href="/simu-learn/comsol/basics/materials.html">材料设置</a></li><li><a href="/simu-learn/comsol/basics/mesh.html">网格划分</a></li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>善用模型树可以快速导航和修改仿真设置，这是 COMSOL 操作的核心。</p></div><div class="info custom-block"><p class="custom-block-title">小知识</p><p>COMSOL 支持多窗口操作，可以同时查看几何、网格和结果。</p></div>`,60)])])}const u=a(e,[["render",l]]);export{b as __pageData,u as default};
